// PHASE 4: INPATIENT-PATTERN CALL SCHEDULING
console.log('=== PHASE 4: INPATIENT-PATTERN CALL SCHEDULING ===');

const allItems = $input.all();
console.log(`Received ${allItems.length} items from merge`);

let inpatientScheduleRecords = [];
let activeFaculty = [];
let phase0AbsenceData = null;
let phase3EnhancedResults = null;

allItems.forEach(item => {
  const data = item.json;

  if (data.phase === 0 && data.absence_data) {
    phase0AbsenceData = data.absence_data;
  } else if (data.phase === 3 && data.enhanced_faculty_assignments) {
    phase3EnhancedResults = data;
  } else if (data['Inpatient Week Start'] || data['Block Number']) {
    inpatientScheduleRecords.push(data);
  } else if (data['Faculty'] && data['Last Name'] && !data['Leave Start']) {
    activeFaculty.push(data);
  }
});

console.log(`Found: ${inpatientScheduleRecords.length} inpatient schedule records`);
console.log(`Found: ${activeFaculty.length} active faculty`);
console.log(`Phase 0 absence data: ${phase0AbsenceData ? 'Available' : 'Not available'}`);
console.log(`Phase 3 enhanced results: ${phase3EnhancedResults ? 'Available' : 'Not available'}`);

const facultyAbsences = phase0AbsenceData ? (phase0AbsenceData.facultyAbsences || {}) : {};

const daysOfWeek = [
  { day: 'Friday', callField: 'Friday Call', dateField: 'Friday Date', isInpatientEligible: true },
  { day: 'Saturday', callField: 'Saturday Call', dateField: 'Saturday Date', isInpatientEligible: true },
  { day: 'Sunday', callField: 'Sunday Call', dateField: 'Sunday Date', isInpatientEligible: false },
  { day: 'Monday', callField: 'Monday Call', dateField: 'Monday Date', isInpatientEligible: false },
  { day: 'Tuesday', callField: 'Tuesday Call', dateField: 'Tuesday Date', isInpatientEligible: false },
  { day: 'Wednesday', callField: 'Wednesday Call', dateField: 'Wednesday Date', isInpatientEligible: false },
  { day: 'Thursday', callField: 'Thursday Call', dateField: 'Thursday Date', isInpatientEligible: false }
];

const callAssignments = [];
const facultyCallCounts = {};
const facultyLastCallDate = {};

activeFaculty.forEach(faculty => {
  const facultyId = faculty.id || faculty['Faculty ID'];
  facultyCallCounts[facultyId] = 0;
  facultyLastCallDate[facultyId] = null;
});

function isFacultyAvailable(facultyId, date) {
  if (facultyAbsences[facultyId] && facultyAbsences[facultyId][date]) {
    return false;
  }
  return true;
}

function getDaysSinceLastCall(facultyId, currentDate) {
  if (!facultyLastCallDate[facultyId]) return Infinity;
  const lastDate = new Date(facultyLastCallDate[facultyId]);
  const current = new Date(currentDate);
  return Math.floor((current - lastDate) / (1000 * 60 * 60 * 24));
}

function selectNonInpatientFaculty(date, inpatientFacultyIds, dayOfWeek) {
  const eligible = activeFaculty.filter(faculty => {
    const facultyId = faculty.id || faculty['Faculty ID'];
    if (inpatientFacultyIds.includes(facultyId)) return false;
    if (!isFacultyAvailable(facultyId, date)) return false;
    return true;
  });

  if (eligible.length === 0) return null;

  eligible.sort((a, b) => {
    const aId = a.id || a['Faculty ID'];
    const bId = b.id || b['Faculty ID'];
    const aDays = getDaysSinceLastCall(aId, date);
    const bDays = getDaysSinceLastCall(bId, date);
    if (aDays !== bDays) return bDays - aDays;
    return (facultyCallCounts[aId] || 0) - (facultyCallCounts[bId] || 0);
  });

  return eligible[0].id || eligible[0]['Faculty ID'];
}

inpatientScheduleRecords.forEach((record, recordIndex) => {
  const blockNumber = record['Block Number'];
  const weekOfBlock = record['Week Of Block'];
  const inpatientWeekStart = record['Inpatient Week Start'];
  const inpatientWeekEnd = record['Inpatient Week End'];

  const inpatientFacultyIds = [];

  daysOfWeek.forEach(dayConfig => {
    const callFieldValue = record[dayConfig.callField];
    const dateFieldValue = record[dayConfig.dateField];

    if (!dateFieldValue) return;

    let assignedFacultyId = null;
    let assignmentMethod = null;

    if (dayConfig.isInpatientEligible) {
      if (callFieldValue && Array.isArray(callFieldValue) && callFieldValue.length > 0) {
        assignedFacultyId = callFieldValue[0];
        if (!inpatientFacultyIds.includes(assignedFacultyId)) {
          inpatientFacultyIds.push(assignedFacultyId);
        }
        assignmentMethod = 'Inpatient Faculty (Mandatory)';
      }
    } else {
      assignedFacultyId = selectNonInpatientFaculty(dateFieldValue, inpatientFacultyIds, dayConfig.day);
      assignmentMethod = 'Non-Inpatient Faculty (Inpatient Excluded)';
    }

    if (assignedFacultyId) {
      const assignedFaculty = activeFaculty.find(f => (f.id || f['Faculty ID']) === assignedFacultyId);
      const facultyName = assignedFaculty ? (assignedFaculty.Faculty || assignedFaculty['Last Name']) : 'Unknown';

      callAssignments.push({
        date: dateFieldValue,
        dayOfWeek: dayConfig.day.toLowerCase(),
        assignedFaculty: assignedFacultyId,
        facultyName: facultyName,
        callType: 'Overnight Call',
        assignmentMethod: assignmentMethod,
        isInpatientDay: dayConfig.isInpatientEligible,
        blockNumber: blockNumber,
        weekOfBlock: weekOfBlock,
        inpatientWeekStart: inpatientWeekStart,
        inpatientWeekEnd: inpatientWeekEnd,
        phase0Integration: phase0AbsenceData ? true : false
      });

      facultyCallCounts[assignedFacultyId] = (facultyCallCounts[assignedFacultyId] || 0) + 1;
      facultyLastCallDate[assignedFacultyId] = dateFieldValue;
    } else {
      console.log(`WARNING: Could not assign faculty for ${dayConfig.day} ${dateFieldValue}`);
    }
  });
});

const facultyUtilization = activeFaculty.map(faculty => {
  const facultyId = faculty.id || faculty['Faculty ID'];
  return {
    facultyId: facultyId,
    facultyName: faculty.Faculty || faculty['Last Name'],
    totalCallsAssigned: facultyCallCounts[facultyId] || 0,
    lastCallDate: facultyLastCallDate[facultyId],
    absenceDays: facultyAbsences[facultyId] ? Object.keys(facultyAbsences[facultyId]).length : 0
  };
});

const statistics = {
  totalInpatientWeeks: inpatientScheduleRecords.length,
  totalCallDates: callAssignments.length,
  fridaySaturdayInpatientCalls: callAssignments.filter(a => a.isInpatientDay).length,
  sundayThursdayNonInpatientCalls: callAssignments.filter(a => !a.isInpatientDay).length,
  totalActiveFaculty: activeFaculty.length,
  phase0Integration: phase0AbsenceData ? true : false,
  phase3Integration: phase3EnhancedResults ? true : false
};

console.log('\n=== PHASE 4 RESULTS ===');
console.log(`Total inpatient weeks processed: ${statistics.totalInpatientWeeks}`);
console.log(`Total call assignments: ${statistics.totalCallDates}`);
console.log(`Friday/Saturday (inpatient): ${statistics.fridaySaturdayInpatientCalls}`);
console.log(`Sunday-Thursday (non-inpatient): ${statistics.sundayThursdayNonInpatientCalls}`);

return [{
  json: {
    phase: 4,
    phase_name: 'Inpatient-Pattern Call Scheduling',
    success: true,
    call_assignments: callAssignments,
    faculty_utilization: facultyUtilization,
    statistics: statistics,
    configuration: {
      inpatientDays: ['Friday', 'Saturday'],
      nonInpatientDays: ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday'],
      clinicalWeekPattern: 'Friday to Thursday'
    },
    next_phase: 6,
    ready_for_phase6: callAssignments.length > 0,
    processing_timestamp: new Date().toISOString()
  }
}];

const input = $input.first().json;
const callAssignments = input.call_assignments || [];

console.log(`Formatting ${callAssignments.length} call assignments for Airtable`);

const airtableRecords = callAssignments.map(assignment => ({
  fields: {
    'Faculty': [assignment.assignedFaculty],
    'Call Date': assignment.date,
    'Day of Week': assignment.dayOfWeek,
    'Call Type': assignment.callType,
    'Assignment Method': assignment.assignmentMethod,
    'Is Inpatient Day': assignment.isInpatientDay,
    'Block Number': assignment.blockNumber,
    'Week Of Block': assignment.weekOfBlock,
    'Processing Phase': 'Phase 4 - Inpatient-Pattern Call Scheduling'
  },
  _metadata: {
    facultyName: assignment.facultyName,
    inpatientWeekStart: assignment.inpatientWeekStart,
    inpatientWeekEnd: assignment.inpatientWeekEnd
  }
}));

console.log(`Created ${airtableRecords.length} Airtable-ready records`);

return airtableRecords.map(record => ({ json: record }));

