console.log('=== PHASE 4 COMPLETION SUMMARY ===');

const phase4Results = $('Phase 4: Inpatient-Pattern Call Engine').first().json;
const airtableResults = $input.all();

const successfulCreations = airtableResults.filter(result => 
  result.json && result.json.records && result.json.records.length > 0
).length;

const stats = phase4Results.statistics;

const completionSummary = {
  phase: 4,
  phase_name: 'Inpatient-Pattern Call Scheduling Complete',
  results: {
    total_inpatient_weeks: stats.totalInpatientWeeks,
    total_call_assignments: stats.totalCallDates,
    friday_saturday_inpatient: stats.fridaySaturdayInpatientCalls,
    sunday_thursday_non_inpatient: stats.sundayThursdayNonInpatientCalls,
    airtable_records_created: successfulCreations
  },
  pattern_compliance: {
    inpatient_days_covered: stats.fridaySaturdayInpatientCalls > 0,
    non_inpatient_days_covered: stats.sundayThursdayNonInpatientCalls > 0,
    clinical_week_pattern: 'Friday to Thursday',
    inpatient_exclusion_active: true
  },
  next_phase: 6,
  ready_for_phase6: successfulCreations > 0,
  processing_complete: new Date().toISOString()
};

console.log(`Total call assignments: ${stats.totalCallDates}`);
console.log(`Friday/Saturday (inpatient): ${stats.fridaySaturdayInpatientCalls}`);
console.log(`Sunday-Thursday (non-inpatient): ${stats.sundayThursdayNonInpatientCalls}`);
console.log(`Airtable records created: ${successfulCreations}`);

return [{ json: completionSummary }];
